const data = items[0].json.data || items[0].json;

const gameLabels = { cod_mobile: '🎯 کالاف موبایل', fortnite: '🏗️ فورتنایت', clash_royale: '👑 کلش رویال' };
const game = gameLabels[data.game] || data.game;
const start = data.startDate ? new Date(data.startDate) : null;
const startStr = start ? start.toLocaleString('fa-IR', {dateStyle:'medium', timeStyle:'short', timeZone:'Asia/Tehran'}) : 'اعلام می‌شود';

const text = [
  '🏆 <b>تورنومنت جدید در گیمنت</b>',
  '',
  `🔥 <b>${data.name}</b>`,
  `🎮 بازی: <b>${game}</b>`,
  data.gameMode ? `🕹 مود: ${data.gameMode}` : '',
  `👥 ظرفیت: <b>${data.maxPlayers || 16} نفر</b>`,
  `💳 ورودی: <b>${data.entryFee || 'رایگان'}</b>`,
  data.prizePool ? `🎁 جایزه: <b>${data.prizePool}</b>` : '',
  `⏰ شروع: <b>${startStr}</b>`,
  '',
  'برای ثبت‌نام و جزئیات بیشتر وارد اپ شوید 👇'
].filter(Boolean).join('\n');

const now = new Date();
let hoursUntil = null, wait24h = 0, wait1h = 0;
if (start) {
  const diffMs = start.getTime() - now.getTime();
  hoursUntil = Math.round(diffMs / (1000*60*60));
  wait24h = Math.max(0, diffMs - (24*60*60*1000));
  wait1h  = Math.max(0, diffMs - (1*60*60*1000));
}

return [{
  json: {
    ...data,
    telegramText: text,
    channelId: process.env.TELEGRAM_CHANNEL_ID || '@Gament_games',
    appUrl: process.env.APP_URL || 'https://www.gament1.ir',
    hoursUntilStart: hoursUntil,
    waitFor24h: Math.floor(wait24h / 1000),
    waitFor1h: Math.floor(wait1h / 1000),
    hasStartDate: !!start
  }
}];

const d = items[0].json;
const txt = [
  '⏰ <b>یادآوری ۲۴ ساعته</b>',
  '',
  `🔥 <b>${d.name}</b>`,
  `🎮 ${d.game}`,
  `⏰ کمتر از ۲۴ ساعت تا شروع`,
  '',
  'ثبت‌نام کن 👇'
].join('\n');
return [{ json: { ...d, reminderText: txt, reminderType: '24h' } }];

const d = items[0].json;
const txt = [
  '🚨 <b>یادآوری نهایی - ۱ ساعت مانده</b>',
  '',
  `🔥 <b>${d.name}</b>`,
  `🎮 ${d.game}`,
  `⏰ فقط ۱ ساعت تا شروع!`,
  '',
  'به لابی بروید 👇'
].join('\n');
return [{ json: { ...d, reminderText: txt, reminderType: '1h' } }];
